# =============================================================================
# MyConvergio Agent Management
# =============================================================================
# Version: 2.0.0
# =============================================================================

.PHONY: install install-local upgrade test clean update check-sync version help lint validate

# Directories
AGENTS_SRC := .claude/agents
RULES_SRC := .claude/rules
SKILLS_SRC := .claude/skills
CLAUDE_HOME := $(HOME)/.claude
GLOBAL_AGENTS := $(CLAUDE_HOME)/agents
GLOBAL_RULES := $(CLAUDE_HOME)/rules
GLOBAL_SKILLS := $(CLAUDE_HOME)/skills

# Colors
GREEN := \033[0;32m
YELLOW := \033[1;33m
BLUE := \033[0;34m
RED := \033[0;31m
NC := \033[0m

# Default target
.DEFAULT_GOAL := help

help:
	@echo "$(BLUE)MyConvergio Agent Management$(NC)"
	@echo ""
	@echo "$(YELLOW)For New Users:$(NC)"
	@echo "  make install        Install agents, rules, and skills to ~/.claude/"
	@echo ""
	@echo "$(YELLOW)For Existing Users:$(NC)"
	@echo "  make upgrade        Update to latest version (clean + install)"
	@echo ""
	@echo "$(YELLOW)Other Options:$(NC)"
	@echo "  make install-local  Install to current project only (./.claude/)"
	@echo "  make clean          Remove all installed components from ~/.claude/"
	@echo "  make version        Show installed version info"
	@echo ""
	@echo "$(YELLOW)Development:$(NC)"
	@echo "  make test           Run agent tests"
	@echo "  make lint           Lint agent YAML frontmatter"
	@echo "  make validate       Validate Constitution compliance"

install:
	@echo "$(BLUE)Installing MyConvergio to $(CLAUDE_HOME)/...$(NC)"
	@echo ""
	@# Install agents
	@mkdir -p $(GLOBAL_AGENTS)
	@cp -r $(AGENTS_SRC)/* $(GLOBAL_AGENTS)/
	@AGENT_COUNT=$$(find $(GLOBAL_AGENTS) -name '*.md' ! -name 'CONSTITUTION.md' ! -name 'CommonValuesAndPrinciples.md' ! -name 'SECURITY_FRAMEWORK_TEMPLATE.md' | wc -l | tr -d ' '); \
	echo "  $(GREEN)âœ“$(NC) Installed $$AGENT_COUNT agents"
	@# Install rules
	@mkdir -p $(GLOBAL_RULES)
	@cp -r $(RULES_SRC)/* $(GLOBAL_RULES)/
	@RULES_COUNT=$$(find $(GLOBAL_RULES) -name '*.md' | wc -l | tr -d ' '); \
	echo "  $(GREEN)âœ“$(NC) Installed $$RULES_COUNT rules"
	@# Install skills
	@mkdir -p $(GLOBAL_SKILLS)
	@cp -r $(SKILLS_SRC)/* $(GLOBAL_SKILLS)/
	@SKILLS_COUNT=$$(find $(GLOBAL_SKILLS) -type d -mindepth 1 -maxdepth 1 | wc -l | tr -d ' '); \
	echo "  $(GREEN)âœ“$(NC) Installed $$SKILLS_COUNT skills"
	@echo ""
	@echo "$(GREEN)âœ… Installation complete!$(NC)"
	@echo ""
	@echo "$(YELLOW)Note:$(NC) Your ~/.claude/CLAUDE.md was NOT modified."
	@echo "      Create your own or copy from docs/examples/ if needed."

install-local:
	@echo "$(BLUE)Installing to current project ./.claude/...$(NC)"
	@mkdir -p .claude/agents .claude/rules .claude/skills
	@cp -r $(AGENTS_SRC)/* .claude/agents/
	@cp -r $(RULES_SRC)/* .claude/rules/
	@cp -r $(SKILLS_SRC)/* .claude/skills/
	@echo "$(GREEN)âœ… Local installation complete$(NC)"

upgrade:
	@echo "$(BLUE)Upgrading MyConvergio...$(NC)"
	@echo ""
	@# Show current version if exists
	@if [ -f "$(GLOBAL_AGENTS)/core_utility/CONSTITUTION.md" ]; then \
		echo "$(YELLOW)Current installation found. Removing old version...$(NC)"; \
	else \
		echo "$(YELLOW)No previous installation found. Installing fresh...$(NC)"; \
	fi
	@$(MAKE) clean --no-print-directory
	@$(MAKE) install --no-print-directory
	@echo ""
	@echo "$(GREEN)âœ… Upgrade complete!$(NC)"

clean:
	@echo "$(BLUE)Removing installed components...$(NC)"
	@rm -rf $(GLOBAL_AGENTS)/* 2>/dev/null || true
	@rm -rf $(GLOBAL_RULES)/* 2>/dev/null || true
	@rm -rf $(GLOBAL_SKILLS)/* 2>/dev/null || true
	@echo "  $(GREEN)âœ“$(NC) Cleaned ~/.claude/agents/"
	@echo "  $(GREEN)âœ“$(NC) Cleaned ~/.claude/rules/"
	@echo "  $(GREEN)âœ“$(NC) Cleaned ~/.claude/skills/"
	@echo ""
	@echo "$(YELLOW)Note:$(NC) ~/.claude/CLAUDE.md was NOT removed (user config)."

version:
	@echo "$(BLUE)MyConvergio Version Info$(NC)"
	@echo ""
	@cat VERSION | head -6
	@echo ""
	@echo "$(BLUE)Installed Components:$(NC)"
	@if [ -d "$(GLOBAL_AGENTS)" ]; then \
		AGENT_COUNT=$$(find $(GLOBAL_AGENTS) -name '*.md' 2>/dev/null | wc -l | tr -d ' '); \
		echo "  Agents: $$AGENT_COUNT"; \
	else \
		echo "  Agents: $(RED)not installed$(NC)"; \
	fi
	@if [ -d "$(GLOBAL_RULES)" ]; then \
		RULES_COUNT=$$(find $(GLOBAL_RULES) -name '*.md' 2>/dev/null | wc -l | tr -d ' '); \
		echo "  Rules:  $$RULES_COUNT"; \
	else \
		echo "  Rules:  $(RED)not installed$(NC)"; \
	fi
	@if [ -d "$(GLOBAL_SKILLS)" ]; then \
		SKILLS_COUNT=$$(find $(GLOBAL_SKILLS) -type d -mindepth 1 -maxdepth 1 2>/dev/null | wc -l | tr -d ' '); \
		echo "  Skills: $$SKILLS_COUNT"; \
	else \
		echo "  Skills: $(RED)not installed$(NC)"; \
	fi

test:
	@echo "$(BLUE)Running agent tests...$(NC)"
	@./scripts/test-deployment.sh

lint:
	@echo "$(BLUE)Linting agent YAML frontmatter...$(NC)"
	@for file in $$(find $(AGENTS_SRC) -name '*.md' ! -name 'CONSTITUTION.md' ! -name 'CommonValuesAndPrinciples.md' ! -name 'SECURITY_FRAMEWORK_TEMPLATE.md' ! -name 'MICROSOFT_VALUES.md'); do \
		if ! head -1 "$$file" | grep -q '^---$$'; then \
			echo "$(YELLOW)Warning: $$file missing YAML frontmatter$(NC)"; \
		fi; \
	done
	@echo "$(GREEN)âœ… Lint complete$(NC)"

validate:
	@echo "$(BLUE)Validating Constitution compliance...$(NC)"
	@CONSTITUTION="$(AGENTS_SRC)/core_utility/CONSTITUTION.md"; \
	if [ ! -f "$$CONSTITUTION" ]; then \
		echo "$(YELLOW)Warning: CONSTITUTION.md not found$(NC)"; \
		exit 1; \
	fi
	@echo "$(GREEN)âœ… Constitution found$(NC)"
	@echo "$(BLUE)Checking agents for security framework...$(NC)"
	@MISSING=0; \
	for file in $$(find $(AGENTS_SRC) -name '*.md' ! -name 'CONSTITUTION.md' ! -name 'CommonValuesAndPrinciples.md'); do \
		if ! grep -q "Security" "$$file" 2>/dev/null; then \
			echo "$(YELLOW)Missing security section: $$file$(NC)"; \
			MISSING=$$((MISSING + 1)); \
		fi; \
	done; \
	if [ $$MISSING -gt 0 ]; then \
		echo "$(YELLOW)âڑ ï¸ڈ  $$MISSING agents missing security framework$(NC)"; \
	else \
		echo "$(GREEN)âœ… All agents have security framework$(NC)"; \
	fi

# =============================================================================
# Maintainer Commands (not in help - for internal use)
# =============================================================================

update:
	@echo "$(BLUE)Syncing from ConvergioCLI...$(NC)"
	@./scripts/sync-from-convergiocli.sh

check-sync:
	@echo "$(BLUE)Checking for upstream changes in ConvergioCLI...$(NC)"
	@curl -s "https://api.github.com/repos/Roberdan/convergio-cli/commits?path=src/agents/definitions&per_page=1" 2>/dev/null | \
		grep -E '"sha"|"message"|"date"' | head -6 || echo "Could not fetch (check network)"

message.content:
# API Development Standards

> This rule is enforced by the MyConvergio agent ecosystem.

## Overview
Consistent, well-designed APIs are critical for system integration and developer experience. All APIs in the MyConvergio ecosystem must follow RESTful conventions, implement proper error handling, and provide comprehensive documentation.

## Requirements

### RESTful Conventions

#### HTTP Methods
- **GET**: Retrieve resources (idempotent, no side effects)
- **POST**: Create new resources
- **PUT**: Replace entire resource (idempotent)
- **PATCH**: Partial update of resource (idempotent)
- **DELETE**: Remove resource (idempotent)
- Never use GET for operations with side effects

#### Resource Naming
- Use plural nouns for collections: `/api/users`, `/api/products`
- Use specific identifiers: `/api/users/{userId}`
- Nested resources for relationships: `/api/users/{userId}/orders`
- Use kebab-case for multi-word resources: `/api/payment-methods`
- Avoid verbs in URLs (use HTTP methods instead)
- Keep URLs shallow (max 3 levels deep)

#### HTTP Status Codes
- **200 OK**: Successful GET, PUT, PATCH, or DELETE
- **201 Created**: Successful POST that creates a resource
- **204 No Content**: Successful request with no response body (DELETE)
- **400 Bad Request**: Invalid request (validation errors)
- **401 Unauthorized**: Authentication required
- **403 Forbidden**: Authenticated but not authorized
- **404 Not Found**: Resource doesn't exist
- **409 Conflict**: Request conflicts with current state
- **422 Unprocessable Entity**: Validation errors (semantic issues)
- **429 Too Many Requests**: Rate limit exceeded
- **500 Internal Server Error**: Server-side error
- **503 Service Unavailable**: Temporary unavailability

### Error Response Format
- Consistent error response structure across all endpoints
- Include error code, message, and details
- Provide helpful error messages for developers
- Never expose internal implementation details
- Include request ID for tracking

### Pagination
- Implement pagination for all list endpoints
- Support page-based or cursor-based pagination
- Include metadata: total count, page info, links
- Use consistent query parameters: `page`, `limit`, `cursor`
- Default limit should be reasonable (e.g., 20-50)
- Maximum limit to prevent abuse (e.g., 100)

### Filtering and Sorting
- Support filtering via query parameters
- Use consistent naming: `?status=active&category=books`
- Support sorting: `?sort=createdAt&order=desc`
- Allow multiple sort fields: `?sort=priority,createdAt`
- Document available filters and sort fields

### Versioning Strategy
- Version all public APIs from the start
- Use URL versioning: `/api/v1/users` or `/api/v2/users`
- Alternative: Header versioning: `Accept: application/vnd.myapp.v1+json`
- Maintain backwards compatibility within major versions
- Document deprecation timeline for old versions
- Support at least 2 major versions simultaneously

### Rate Limiting
- Implement rate limiting on all public endpoints
- Return `429 Too Many Requests` when limit exceeded
- Include headers: `X-RateLimit-Limit`, `X-RateLimit-Remaining`, `X-RateLimit-Reset`
- Different limits for authenticated vs anonymous users
- Document rate limits in API documentation

### Authentication & Authorization
- Use standard authentication (OAuth 2.0, JWT)
- Include authentication in headers: `Authorization: Bearer {token}`
- Return `401` for missing/invalid authentication
- Return `403` for insufficient permissions
- Validate authorization on every request

### API Documentation
- Use OpenAPI/Swagger specification
- Document all endpoints, parameters, and responses
- Include request/response examples
- Provide interactive API explorer (Swagger UI)
- Keep documentation in sync with implementation
- Version documentation with the API

### CORS Configuration
- Configure CORS for browser-based clients
- Whitelist allowed origins (avoid `*` in production)
- Specify allowed methods and headers
- Handle preflight requests properly

## Examples

### Good Examples

#### RESTful Resource Design
```typescript
// Good: RESTful endpoint structure
GET    /api/v1/users              // List all users
POST   /api/v1/users              // Create new user
GET    /api/v1/users/{userId}     // Get specific user
PUT    /api/v1/users/{userId}     // Replace user
PATCH  /api/v1/users/{userId}     // Update user
DELETE /api/v1/users/{userId}     // Delete user

// Good: Nested resources
GET    /api/v1/users/{userId}/orders           // User's orders
POST   /api/v1/users/{userId}/orders           // Create order for user
GET    /api/v1/users/{userId}/orders/{orderId} // Specific order
```

#### Error Response Format
```typescript
// Good: Consistent error structure
interface ErrorResponse {
  error: {
    code: string;
    message: string;
    details?: Record<string, string[]>;
    requestId: string;
    timestamp: string;
  };
}

// Example response
{
  "error": {
    "code": "VALIDATION_ERROR",
    "message": "Request validation failed",
    "details": {
      "email": ["Email is required", "Email format is invalid"],
      "age": ["Age must be at least 18"]
    },
    "requestId": "req_abc123",
    "timestamp": "2025-12-15T10:30:00Z"
  }
}
```

#### Pagination Response
```typescript
// Good: Comprehensive pagination metadata
{
  "data": [
    { "id": "1", "name": "User 1" },
    { "id": "2", "name": "User 2" }
  ],
  "pagination": {
    "page": 2,
    "limit": 20,
    "total": 150,
    "totalPages": 8,
    "hasNext": true,
    "hasPrev": true
  },
  "links": {
    "first": "/api/v1/users?page=1&limit=20",
    "prev": "/api/v1/users?page=1&limit=20",
    "self": "/api/v1/users?page=2&limit=20",
    "next": "/api/v1/users?page=3&limit=20",
    "last": "/api/v1/users?page=8&limit=20"
  }
}
```

#### Rate Limiting Implementation
```typescript
// Good: Rate limiting with informative headers
app.use('/api', rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  standardHeaders: true, // Return rate limit info in headers
  legacyHeaders: false,
  handler: (req, res) => {
    res.status(429).json({
      error: {
        code: 'RATE_LIMIT_EXCEEDED',
        message: 'Too many requests, please try again later',
        retryAfter: req.rateLimit.resetTime,
        requestId: req.id,
        timestamp: new Date().toISOString()
      }
    });
  }
}));

// Response headers:
// X-RateLimit-Limit: 100
// X-RateLimit-Remaining: 0
// X-RateLimit-Reset: 1702641600
```

#### Proper Status Code Usage
```typescript
// Good: Appropriate status codes
app.post('/api/v1/users', async (req, res) => {
  try {
    // Validate input
    const validation = validateUserInput(req.body);
    if (!validation.valid) {
      return res.status(400).json({
        error: {
          code: 'VALIDATION_ERROR',
          message: 'Invalid input',
          details: validation.errors
        }
      });
    }

    // Check for conflicts
    const existingUser = await findUserByEmail(req.body.email);
    if (existingUser) {
      return res.status(409).json({
        error: {
          code: 'USER_ALREADY_EXISTS',
          message: 'User with this email already exists'
        }
      });
    }

    // Create user
    const user = await createUser(req.body);

    // Return 201 Created with Location header
    res.status(201)
       .location(`/api/v1/users/${user.id}`)
       .json({ data: user });
  } catch (error) {
    // Return 500 for unexpected errors
    res.status(500).json({
      error: {
        code: 'INTERNAL_ERROR',
        message: 'An unexpected error occurred',
        requestId: req.id
      }
    });
  }
});
```

#### Filtering and Sorting
```typescript
// Good: Flexible filtering and sorting
GET /api/v1/products?category=electronics&minPrice=100&maxPrice=500&sort=price&order=asc

app.get('/api/v1/products', async (req, res) => {
  const {
    category,
    minPrice,
    maxPrice,
    sort = 'createdAt',
    order = 'desc',
    page = 1,
    limit = 20
  } = req.query;

  const filters = {};
  if (category) filters.category = category;
  if (minPrice) filters.price = { $gte: Number(minPrice) };
  if (maxPrice) filters.price = { ...filters.price, $lte: Number(maxPrice) };

  const products = await findProducts({
    filters,
    sort: { [sort]: order === 'asc' ? 1 : -1 },
    page: Number(page),
    limit: Number(limit)
  });

  res.json({
    data: products.items,
    pagination: products.pagination
  });
});
```

