@pytest.fixture
def sample_user():
    """Create a sample user for testing."""
    return User(
        id="123",
        email="test@example.com",
        name="Test User",
        is_premium=True
    )

@pytest.fixture
def user_factory():
    """Factory for creating test users with custom attributes."""
    def _create_user(**kwargs):
        defaults = {
            "email": "test@example.com",
            "name": "Test User",
            "is_premium": False
        }
        return User(**{**defaults, **kwargs})
    return _create_user

def test_with_factory(user_factory):
