		echo "  Agents: $$AGENT_COUNT"; \
	else \
		echo "  Agents: $(RED)not installed$(NC)"; \
	fi
	@if [ -d "$(GLOBAL_RULES)" ]; then \
		RULES_COUNT=$$(find $(GLOBAL_RULES) -name '*.md' 2>/dev/null | wc -l | tr -d ' '); \
		echo "  Rules:  $$RULES_COUNT"; \
	else \
		echo "  Rules:  $(RED)not installed$(NC)"; \
	fi
