     1â†’#!/usr/bin/env node
     2â†’
     3â†’/**
     4â†’ * MyConvergio Post-Install Script
     5â†’ *
     6â†’ * Automatically copies agents, rules, and skills to ~/.claude/
     7â†’ * after npm install -g myconvergio
     8â†’ *
     9â†’ * Features:
    10â†’ * - Creates backup if existing installation found
    11â†’ * - Saves manifest of installed files for safe uninstall
    12â†’ * - Preserves user's custom files and CLAUDE.md
    13â†’ */
    14â†’
    15â†’const fs = require('fs');
    16â†’const path = require('path');
    17â†’const os = require('os');
    18â†’
    19â†’const CLAUDE_HOME = path.join(os.homedir(), '.claude');
    20â†’const PACKAGE_ROOT = path.join(__dirname, '..');
    21â†’const MANIFEST_FILE = path.join(CLAUDE_HOME, '.myconvergio-manifest.json');
    22â†’
    23â†’// Colors for terminal output
    24â†’const colors = {
    25â†’  reset: '\x1b[0m',
    26â†’  green: '\x1b[32m',
    27â†’  yellow: '\x1b[33m',
    28â†’  blue: '\x1b[34m',
    29â†’};
    30â†’
    31â†’function log(color, message) {
    32â†’  // Use stderr for npm postinstall visibility (npm suppresses stdout)
    33â†’  process.stderr.write(`${color}${message}${colors.reset}\n`);
    34â†’}
    35â†’
    36â†’function copyRecursive(src, dest, installedFiles = []) {
    37â†’  if (!fs.existsSync(src)) {
    38â†’    return installedFiles;
    39â†’  }
    40â†’
    41â†’  fs.mkdirSync(dest, { recursive: true });
    42â†’
    43â†’  const items = fs.readdirSync(src);
    44â†’
    45â†’  for (const item of items) {
    46â†’    const srcPath = path.join(src, item);
    47â†’    const destPath = path.join(dest, item);
    48â†’    const stat = fs.statSync(srcPath);
    49â†’
    50â†’    if (stat.isDirectory()) {
    51â†’      copyRecursive(srcPath, destPath, installedFiles);
    52â†’    } else {
    53â†’      fs.copyFileSync(srcPath, destPath);
    54â†’      installedFiles.push(destPath);
    55â†’    }
    56â†’  }
    57â†’
    58â†’  return installedFiles;
    59â†’}
    60â†’
    61â†’function loadManifest() {
    62â†’  try {
    63â†’    if (fs.existsSync(MANIFEST_FILE)) {
    64â†’      return JSON.parse(fs.readFileSync(MANIFEST_FILE, 'utf8'));
    65â†’    }
    66â†’  } catch {}
    67â†’  return { files: [], version: null };
    68â†’}
    69â†’
    70â†’function saveManifest(files, version) {
    71â†’  const manifest = {
    72â†’    version,
    73â†’    installedAt: new Date().toISOString(),
    74â†’    files
    75â†’  };
    76â†’  fs.mkdirSync(CLAUDE_HOME, { recursive: true });
    77â†’  fs.writeFileSync(MANIFEST_FILE, JSON.stringify(manifest, null, 2));
    78â†’}
    79â†’
    80â†’function getVersion() {
    81â†’  try {
    82â†’    const versionFile = path.join(PACKAGE_ROOT, 'VERSION');
    83â†’    const content = fs.readFileSync(versionFile, 'utf8');
    84â†’    const match = content.match(/SYSTEM_VERSION=(.+)/);
    85â†’    return match ? match[1].trim() : 'unknown';
    86â†’  } catch {
    87â†’    const pkg = require('../package.json');
    88â†’    return pkg.version;
    89â†’  }
    90â†’}
    91â†’
    92â†’function createBackup() {
    93â†’  const backupDir = path.join(os.homedir(), '.claude-backup-' + Date.now());
    94â†’  const dirs = ['agents', 'rules', 'skills'];
    95â†’  let hasContent = false;
    96â†’
    97â†’  for (const dir of dirs) {
    98â†’    const srcDir = path.join(CLAUDE_HOME, dir);
    99â†’    if (fs.existsSync(srcDir) && fs.readdirSync(srcDir).length > 0) {
   100â†’      hasContent = true;
   101â†’      copyRecursive(srcDir, path.join(backupDir, dir));
   102â†’    }
   103â†’  }
   104â†’
   105â†’  return hasContent ? backupDir : null;
   106â†’}
   107â†’
   108â†’function countDirs(dir) {
   109â†’  if (!fs.existsSync(dir)) return 0;
   110â†’  return fs.readdirSync(dir).filter(f =>
   111â†’    fs.statSync(path.join(dir, f)).isDirectory()
   112â†’  ).length;
   113â†’}
   114â†’
   115â†’function hasExistingContent() {
   116â†’  const dirs = ['agents', 'rules', 'skills'];
   117â†’  for (const dir of dirs) {
   118â†’    const dirPath = path.join(CLAUDE_HOME, dir);
   119â†’    if (fs.existsSync(dirPath) && fs.readdirSync(dirPath).length > 0) {
   120â†’      return true;
   121â†’    }
   122â†’  }
   123â†’  return false;
   124â†’}
   125â†’
   126â†’function main() {
   127â†’  // Skip if running in CI or if MYCONVERGIO_SKIP_POSTINSTALL is set
   128â†’  if (process.env.CI || process.env.MYCONVERGIO_SKIP_POSTINSTALL) {
   129â†’    console.log('Skipping postinstall (CI environment or MYCONVERGIO_SKIP_POSTINSTALL set)');
   130â†’    return;
   131â†’  }
   132â†’
   133â†’  log(colors.blue, '\nًں“¦ MyConvergio Post-Install\n');
   134â†’
   135â†’  const srcAgents = path.join(PACKAGE_ROOT, '.claude', 'agents');
   136â†’  const srcRules = path.join(PACKAGE_ROOT, '.claude', 'rules');
   137â†’  const srcSkills = path.join(PACKAGE_ROOT, '.claude', 'skills');
