#!/usr/bin/env node

/**
 * MyConvergio Post-Install Script
 *
 * Automatically copies agents, rules, and skills to ~/.claude/
 * after npm install -g myconvergio
 *
 * Features:
 * - MINIMAL install by default (8 core agents) to save context
 * - Supports MYCONVERGIO_PROFILE env var (minimal|standard|full|lean)
 * - Creates backup if existing installation found
 * - Saves manifest of installed files for safe uninstall
 * - Preserves user's custom files and CLAUDE.md
 */

const fs = require('fs');
const path = require('path');
const os = require('os');

const CLAUDE_HOME = path.join(os.homedir(), '.claude');
const PACKAGE_ROOT = path.join(__dirname, '..');
const MANIFEST_FILE = path.join(CLAUDE_HOME, '.myconvergio-manifest.json');

// Installation profiles
const PROFILES = {
  minimal: {
    name: 'Minimal',
    description: '8 core agents (~50KB)',
    agents: [
      'leadership_strategy/ali-chief-of-staff.md',
      'core_utility/thor-quality-assurance-guardian.md',
      'core_utility/strategic-planner.md',
      'technical_development/baccio-tech-architect.md',
      'technical_development/rex-code-reviewer.md',
      'technical_development/dario-debugger.md',
      'technical_development/otto-performance-optimizer.md',
      'release_management/app-release-manager.md',
    ],
    includeCore: true, // CONSTITUTION.md, CommonValuesAndPrinciples.md
  },
  standard: {
    name: 'Standard',
    description: '25 essential agents (~200KB)',
    categories: [
      'leadership_strategy',
      'technical_development',
      'release_management',
      'compliance_legal',
      'core_utility',
    ],
  },
  full: {
    name: 'Full',
    description: 'All 57 agents (~800KB)',
    categories: 'all',
  },
  lean: {
    name: 'Lean',
    description: 'All agents with stripped frameworks (~400KB)',
    useLean: true,
  },
};

// Core files always installed
const CORE_FILES = [
  'core_utility/CONSTITUTION.md',
  'core_utility/CommonValuesAndPrinciples.md',
  'core_utility/SECURITY_FRAMEWORK_TEMPLATE.md',
  'core_utility/MICROSOFT_VALUES.md',
];

// Colors for terminal output
const colors = {
  reset: '\x1b[0m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
};

function log(color, message) {
  process.stderr.write(`${color}${message}${colors.reset}\n`);
}

function copyFile(src, dest, installedFiles) {
  const destDir = path.dirname(dest);
  fs.mkdirSync(destDir, { recursive: true });
  fs.copyFileSync(src, dest);
  installedFiles.push(dest);
}

function copyRecursive(src, dest, installedFiles = []) {
  if (!fs.existsSync(src)) {
    return installedFiles;
  }

  fs.mkdirSync(dest, { recursive: true });

  const items = fs.readdirSync(src);

  for (const item of items) {
    const srcPath = path.join(src, item);
    const destPath = path.join(dest, item);
    const stat = fs.statSync(srcPath);

    if (stat.isDirectory()) {
      copyRecursive(srcPath, destPath, installedFiles);
    } else {
      fs.copyFileSync(srcPath, destPath);
      installedFiles.push(destPath);
    }
  }

  return installedFiles;
}

function loadManifest() {
  try {
    if (fs.existsSync(MANIFEST_FILE)) {
      return JSON.parse(fs.readFileSync(MANIFEST_FILE, 'utf8'));
    }
  } catch {}
  return { files: [], version: null, profile: null };
}

function saveManifest(files, version, profile) {
  const manifest = {
    version,
    profile,
    installedAt: new Date().toISOString(),
    files
  };
  fs.mkdirSync(CLAUDE_HOME, { recursive: true });
  fs.writeFileSync(MANIFEST_FILE, JSON.stringify(manifest, null, 2));
}

function getVersion() {
  try {
    const versionFile = path.join(PACKAGE_ROOT, 'VERSION');
    const content = fs.readFileSync(versionFile, 'utf8');
    const match = content.match(/SYSTEM_VERSION=(.+)/);
    return match ? match[1].trim() : 'unknown';
  } catch {
    const pkg = require('../package.json');
    return pkg.version;
  }
}

function createBackup() {
  const backupDir = path.join(os.homedir(), '.claude-backup-' + Date.now());
  const dirs = ['agents', 'rules', 'skills'];
  let hasContent = false;

  for (const dir of dirs) {
    const srcDir = path.join(CLAUDE_HOME, dir);
    if (fs.existsSync(srcDir) && fs.readdirSync(srcDir).length > 0) {
      hasContent = true;
      copyRecursive(srcDir, path.join(backupDir, dir));
    }
  }

  return hasContent ? backupDir : null;
}

function hasExistingContent() {
  const dirs = ['agents', 'rules', 'skills'];
  for (const dir of dirs) {
    const dirPath = path.join(CLAUDE_HOME, dir);
    if (fs.existsSync(dirPath) && fs.readdirSync(dirPath).length > 0) {
      return true;
    }
  }
  return false;
}

function installMinimalAgents(srcAgents, installedFiles) {
  const profile = PROFILES.minimal;
  const destAgents = path.join(CLAUDE_HOME, 'agents');

  // Install core files first
  for (const coreFile of CORE_FILES) {
    const src = path.join(srcAgents, coreFile);
    if (fs.existsSync(src)) {
      const dest = path.join(destAgents, coreFile);
      copyFile(src, dest, installedFiles);
    }
  }

  // Install selected agents
  for (const agentPath of profile.agents) {
    const src = path.join(srcAgents, agentPath);
    if (fs.existsSync(src)) {
      const dest = path.join(destAgents, agentPath);
      copyFile(src, dest, installedFiles);
    }
  }

  return profile.agents.length;
}

function installStandardAgents(srcAgents, installedFiles) {
  const profile = PROFILES.standard;
  const destAgents = path.join(CLAUDE_HOME, 'agents');
  let count = 0;

  for (const category of profile.categories) {
    const srcCat = path.join(srcAgents, category);
    if (fs.existsSync(srcCat)) {
      const destCat = path.join(destAgents, category);
      copyRecursive(srcCat, destCat, installedFiles);
      count += fs.readdirSync(srcCat).filter(f => f.endsWith('.md')).length;
    }
  }

  return count;
}

function installFullAgents(srcAgents, installedFiles) {
  const destAgents = path.join(CLAUDE_HOME, 'agents');
  copyRecursive(srcAgents, destAgents, installedFiles);

  // Count agents
  let count = 0;
  const countMd = (dir) => {
    const items = fs.readdirSync(dir);
    for (const item of items) {
      const fullPath = path.join(dir, item);
      if (fs.statSync(fullPath).isDirectory()) {
        countMd(fullPath);
      } else if (item.endsWith('.md') && !CORE_FILES.some(f => f.endsWith(item))) {
        count++;
      }
    }
  };
  countMd(destAgents);

  return count;
}

function installLeanAgents(srcAgents, installedFiles) {
  // Check if lean variants exist
  const leanAgents = path.join(PACKAGE_ROOT, '.claude', 'agents-lean');
  if (fs.existsSync(leanAgents)) {
    const destAgents = path.join(CLAUDE_HOME, 'agents');
    copyRecursive(leanAgents, destAgents, installedFiles);
    return 'lean';
  } else {
    // Fallback to full if lean not available
    log(colors.yellow, '  Lean variants not available, using full agents');
    return installFullAgents(srcAgents, installedFiles);
  }
}

function main() {
  // Skip if running in CI or if MYCONVERGIO_SKIP_POSTINSTALL is set
  if (process.env.CI || process.env.MYCONVERGIO_SKIP_POSTINSTALL) {
    console.log('Skipping postinstall (CI environment or MYCONVERGIO_SKIP_POSTINSTALL set)');
    return;
  }

  // Determine profile from env var or default to minimal
  const profileName = (process.env.MYCONVERGIO_PROFILE || 'minimal').toLowerCase();
  const profile = PROFILES[profileName] || PROFILES.minimal;

  log(colors.blue, '\nًں“¦ MyConvergio Post-Install\n');
  log(colors.cyan, `Profile: ${profile.name} (${profile.description})`);
  process.stderr.write('\n');

  const srcAgents = path.join(PACKAGE_ROOT, '.claude', 'agents');
  const srcRules = path.join(PACKAGE_ROOT, '.claude', 'rules');
  const srcSkills = path.join(PACKAGE_ROOT, '.claude', 'skills');

  // Check if source directories exist
  if (!fs.existsSync(srcAgents)) {
    log(colors.yellow, 'Warning: Source agents directory not found. Skipping installation.');
    return;
  }

  // Check for existing content and backup
  const existingManifest = loadManifest();
  const hasContent = hasExistingContent();

  if (existingManifest.version) {
    log(colors.yellow, `Upgrading from v${existingManifest.version} (${existingManifest.profile || 'unknown'} profile)...`);
  } else if (hasContent) {
    log(colors.yellow, 'Existing ~/.claude/ content detected.');
  }

  if (hasContent) {
    log(colors.yellow, 'Creating backup before installation...\n');
    const backupDir = createBackup();
    if (backupDir) {
      log(colors.green, `  âœ“ Backup created: ${backupDir}\n`);
    }
  }

  const installedFiles = [];
  let agentCount = 0;

  // Install agents based on profile
  switch (profileName) {
    case 'minimal':
      agentCount = installMinimalAgents(srcAgents, installedFiles);
      break;
    case 'standard':
      agentCount = installStandardAgents(srcAgents, installedFiles);
      break;
    case 'full':
      agentCount = installFullAgents(srcAgents, installedFiles);
      break;
    case 'lean':
      agentCount = installLeanAgents(srcAgents, installedFiles);
      break;
    default:
      agentCount = installMinimalAgents(srcAgents, installedFiles);
  }

  log(colors.green, `  âœ“ Installed ${agentCount} agents (${profileName})`);

  // Install rules (consolidated by default for minimal, full for others)
  const consolidatedRules = path.join(srcRules, 'consolidated', 'engineering-standards.md');
  if (profileName === 'minimal' && fs.existsSync(consolidatedRules)) {
    const destRules = path.join(CLAUDE_HOME, 'rules');
    fs.mkdirSync(destRules, { recursive: true });
    copyFile(consolidatedRules, path.join(destRules, 'engineering-standards.md'), installedFiles);
    log(colors.green, '  âœ“ Installed consolidated rules (1 file)');
  } else {
    copyRecursive(srcRules, path.join(CLAUDE_HOME, 'rules'), installedFiles);
    log(colors.green, '  âœ“ Installed rules');
  }

  // Install skills
  copyRecursive(srcSkills, path.join(CLAUDE_HOME, 'skills'), installedFiles);
  log(colors.green, '  âœ“ Installed skills');

  // Save manifest
  const version = getVersion();
  saveManifest(installedFiles, version, profileName);
  log(colors.green, `  âœ“ Saved manifest (${installedFiles.length} files)`);

  process.stderr.write('\n');
  log(colors.green, 'âœ… MyConvergio installed successfully!');
  process.stderr.write('\n');

  if (profileName === 'minimal') {
    log(colors.yellow, 'Installed MINIMAL profile to save context.');
    log(colors.cyan, 'For more agents run: myconvergio install --full');
    process.stderr.write('\n');
  }

  log(colors.yellow, 'Your ~/.claude/CLAUDE.md was NOT modified.');
  process.stderr.write('Run `myconvergio help` for available commands.\n\n');
}

main();

