}

function copyAgentsByProfile(srcAgents, destAgents, profile, variant = 'full') {
  const spec = getAgentsForProfile(profile);
  const installedFiles = [];

  fs.mkdirSync(destAgents, { recursive: true });

  // Always copy core utility
  const coreUtilSrc = path.join(srcAgents, 'core_utility');
  const coreUtilDest = path.join(destAgents, 'core_utility');
  if (fs.existsSync(coreUtilSrc)) {
    copyRecursive(coreUtilSrc, coreUtilDest, installedFiles);
  }

  if (spec.agents) {
    // Copy specific agent files
    for (const agentPath of spec.agents) {
      const srcPath = path.join(srcAgents, agentPath);
      const category = path.dirname(agentPath);
      const fileName = path.basename(agentPath);
      const destCategoryDir = path.join(destAgents, category);
      const destPath = path.join(destCategoryDir, fileName);

      if (fs.existsSync(srcPath)) {
        fs.mkdirSync(destCategoryDir, { recursive: true });

        // Check for lean variant if requested
        if (variant === 'lean') {
          const leanSrcPath = srcPath.replace('.md', '.lean.md');
          if (fs.existsSync(leanSrcPath)) {
            fs.copyFileSync(leanSrcPath, destPath);
          } else {
            fs.copyFileSync(srcPath, destPath);
          }
        } else {
          fs.copyFileSync(srcPath, destPath);
        }
        installedFiles.push(destPath);
      }
    }
  } else if (spec.categories) {
    // Copy entire categories
    for (const category of spec.categories) {
      if (category === 'core_utility') continue;
      const srcCat = path.join(srcAgents, category);
      const destCat = path.join(destAgents, category);
      if (fs.existsSync(srcCat)) {
        copyRecursive(srcCat, destCat, installedFiles);
      }
    }
  } else {
    // Full install
    copyRecursive(srcAgents, destAgents, installedFiles);
  }

  return installedFiles;
}

async function promptProfile() {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
  });

  return new Promise((resolve) => {
    console.log('');
    log(colors.blue, 'Select installation profile:\n');
    console.log('  1) minimal  - 8 core agents (~50KB context)');
    console.log('  2) standard - 20 common agents (~200KB context) [recommended]');
    console.log('  3) full     - All 57 agents (~600KB context)');
    console.log('');

    rl.question('Enter your choice (1-3) [2]: ', (answer) => {
      rl.close();
      const choice = answer.trim() || '2';
      const profiles = { '1': 'minimal', '2': 'standard', '3': 'full' };
      resolve(profiles[choice] || 'standard');
    });
  });
}

