  log(colors.green, `  âœ“ Installed ${agentCount} agents`);

  // Install rules (consolidated by default)
  const rulesFile = path.join(srcRules, 'engineering-standards.md');
  if (fs.existsSync(rulesFile)) {
    fs.mkdirSync(path.join(CLAUDE_HOME, 'rules'), { recursive: true });
    fs.copyFileSync(rulesFile, path.join(CLAUDE_HOME, 'rules', 'engineering-standards.md'));
    installedFiles.push(path.join(CLAUDE_HOME, 'rules', 'engineering-standards.md'));
    log(colors.green, '  âœ“ Installed consolidated rules (3.6KB)');
  }

  // Install skills
  copyRecursive(srcSkills, path.join(CLAUDE_HOME, 'skills'), installedFiles);
  const skillsCount = countDirs(path.join(CLAUDE_HOME, 'skills'));
  log(colors.green, `  âœ“ Installed ${skillsCount} skills`);

  // Save manifest
  const version = getVersion();
  saveManifest(installedFiles, version);
  log(colors.green, `  âœ“ Saved manifest (${installedFiles.length} files)`);

  console.log('');
  log(colors.green, 'âœ… Installation complete!');
  console.log('');

  if (profile === 'minimal') {
    log(colors.yellow, 'ًں’، To install more agents:');
    console.log('    myconvergio install --standard   (20 agents)');
    console.log('    myconvergio install --full       (57 agents)');
    console.log('');
  }

  log(colors.yellow, 'Note: Your ~/.claude/CLAUDE.md was NOT modified.');
  console.log('      Create your own configuration file if needed.');
}

function countDirs(dir) {
  if (!fs.existsSync(dir)) return 0;
  return fs.readdirSync(dir).filter(f =>
    fs.statSync(path.join(dir, f)).isDirectory()
  ).length;
}

