  log(colors.green, '  âœ“ Installed skills');

  // Save manifest
  const version = getVersion();
  saveManifest(installedFiles, version);
  log(colors.green, `  âœ“ Saved manifest (${installedFiles.length} files)`);

  console.log('');
  log(colors.green, 'âœ… Installation complete!');
  console.log('');

  if (profile === 'minimal') {
    log(colors.yellow, 'Tip: For more agents run:');
    console.log('  myconvergio install --standard  (25 agents)');
    console.log('  myconvergio install --full      (57 agents)');
    console.log('');
  }

  log(colors.yellow, 'Note: Your ~/.claude/CLAUDE.md was NOT modified.');
  console.log('      Create your own configuration file if needed.');
}

